// Parse projections.json read by the previous node.
// The readWriteFile node returns file content in item.binary or item.data.
// We handle both text and buffer forms.
const items = $input.all();
const raw = items[0].binary?.data
  ? Buffer.from(items[0].binary.data, 'base64').toString('utf-8')
  : (items[0].json?.data ?? items[0].json?.content ?? '');

let projections;
try {
  projections = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to parse projections.json: ' + e.message);
}

// Filter districts where band_sep === 'High' (projected September risk >= 66).
// Threshold defined in engine/engine.py: band() returns 'High' if v >= 66.
const APP_URL = $env.HOZI_APP_URL || 'https://YOUR-GITHUB-PAGES-URL';

const highDistricts = (projections.watch || []).filter(
  d => d.band_sep === 'High'
);

if (highDistricts.length === 0) {
  // No high-band districts — pass a sentinel so the IF node takes the false branch.
  return [{ json: { highCount: 0, alertText: '', districts: [] } }];
}

// Format one alert text covering all high-band districts.
const lines = highDistricts.map(d =>
  `  - ${d.district} (${d.province}): projected Sep risk ${d.projected_sep} — HIGH band. Playbook: ${APP_URL}#${d.district.toLowerCase().replace(/\s+/g, '-')}`
);

const alertText =
  `HOZI ALERT — ${new Date().toISOString().slice(0, 10)}\n` +
  `${highDistricts.length} district(s) projected HIGH food-security risk for September 2026:\n\n` +
  lines.join('\n') +
  `\n\nNational projected Sep mean risk: ${projections.national?.risk_sep ?? 'n/a'}.` +
  `\nReview the full dashboard and Response Planner at ${APP_URL}.` +
  `\n\n-- Hozi automated alert (Layer 0, n8n). Threshold: band_sep=High (score >= 66).`;

return [{ json: { highCount: highDistricts.length, alertText, districts: highDistricts } }];
